#!/usr/bin/env node
// build-bundle.js — Concatenate all dashboard ES modules into a single non-module script.
// Run from the project root: node dashboard/build-bundle.js
// Output: dashboard/js/bundle.js
//
// Each source file is wrapped in its own IIFE so that module-level variables
// (allRows, displayRows, sortKey, etc.) do not collide across panel files.
// Exported names are assigned to the outer scope for cross-file access.

const fs = require('fs');
const path = require('path');

// Order matters: dependencies before dependents
const files = [
  'dashboard/js/utils.js',
  'dashboard/js/parsers.js',
  'dashboard/js/relay-client.js',
  'dashboard/js/panel-printer.js',
  'dashboard/js/panel-inventory.js',
  'dashboard/js/panel-tasks.js',
  'dashboard/js/panel-network.js',
  'dashboard/js/panel-software.js',
  'dashboard/js/tour.js',
  'dashboard/js/app.js',
];

function processFile(rawContent) {
  let content = rawContent;

  // Remove all import lines
  content = content.replace(/^import\s[^'"]*['"][^'"]*['"];?\s*\r?\n?/gm, '');

  // Collect exported names and strip export keyword from declarations
  const exportedNames = [];

  // export function Foo(...) → function Foo(...)
  content = content.replace(/^export\s+function\s+(\w+)/gm, (_m, name) => {
    exportedNames.push(name);
    return `function ${name}`;
  });

  // export const / let / var Foo = ...
  content = content.replace(/^export\s+(const|let|var)\s+(\w+)/gm, (_m, kw, name) => {
    exportedNames.push(name);
    return `${kw} ${name}`;
  });

  // export class Foo
  content = content.replace(/^export\s+class\s+(\w+)/gm, (_m, name) => {
    exportedNames.push(name);
    return `class ${name}`;
  });

  // standalone export { a, b } — extract names, remove line
  content = content.replace(/^export\s*\{([^}]+)\};?\s*\r?\n?/gm, (_m, names) => {
    names.split(',').map(n => n.trim()).filter(Boolean).forEach(n => exportedNames.push(n));
    return '';
  });

  return { content, exportedNames };
}

let outerVars = ''; // variable declarations for exported names in outer IIFE
let inner = '';     // concatenated file contents

for (const file of files) {
  const rawContent = fs.readFileSync(file, 'utf8');
  const { content, exportedNames } = processFile(rawContent);
  const basename = path.basename(file);

  if (exportedNames.length === 0 || file.endsWith('app.js')) {
    // app.js has no exports; just include its content directly in the outer scope
    inner += `\n// ====== ${basename} ======\n${content}\n`;
  } else {
    // Wrap in an IIFE to isolate module-level variables; expose exports to outer scope
    const returnObj = exportedNames.map(n => `${n}: ${n}`).join(', ');
    inner += `
// ====== ${basename} ======
(function () {
${content}
// expose exports to bundle scope
${exportedNames.map(n => `_exports.${n} = ${n};`).join('\n')}
})();
var ${exportedNames.map(n => `${n} = _exports.${n}`).join(', ')};
`;
  }
}

const bundle = `// bundle.js — Auto-generated by dashboard/build-bundle.js. Do not edit directly.
// Regenerate with: node dashboard/build-bundle.js
// Single non-module script — works when served over HTTP and when opened as a local file (file:// URL).
(function () {
'use strict';

// Internal registry for cross-file exports
var _exports = {};

${inner}

})();
`;

const outPath = 'dashboard/js/bundle.js';
fs.writeFileSync(outPath, bundle, 'utf8');
console.log(`Written ${outPath} (${Math.round(bundle.length / 1024)} KB)`);
